args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>

SELECT (ql:millisecondsFromDuration(?time) AS ?millis) WHERE {
  VALUES ?race { wd:Q1334847 wd:Q1330738 }
  ?race p:P1257 ?positionStatement .
  ?positionStatement ps:P1257 wd:Q1 ;
                   pq:P642 wd:Q7197 .
  ?positionStatement ps:P3876 ?time .
}
ORDER BY ASC(?millis)
LIMIT 2

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pr: <http://www.wikidata.org/prop/reference/>

SELECT (xsd:float(?minutes) * 60000 + xsd:float(?seconds) * 1000 AS ?millis)
WHERE {
  VALUES ?race { wd:Q1334847 wd:Q1330738 }
  wd:Q216824 p:P1257 ?statement .
  ?statement 
    ps:P1257 wd:Q1 ;
    pq:P642 wd:Q7197 ;
    pr:P805 ?race ;
    ps:P3876 ?time .
  BIND(STR(?time) AS ?timeStr)
  BIND(STRBEFORE(STRAFTER(?timeStr, 'PT'), 'M') AS ?minutes)
  BIND(STRBEFORE(STRAFTER(?timeStr, 'M'), 'S') AS ?seconds)
}
ORDER BY ASC(?millis)
LIMIT 1
OFFSET 1
